use std::collections::HashMap;
use std::error::Error;
use std::fmt;

#[derive(Debug)]
struct CacheEvent {
    key: String,
    data: String,
}

impl fmt::Display for CacheEvent {
    fn fmt(&self, f: &mut fmt::Formatter) -> Result<(), fmt::Error> {
        write!(f, "Key: {}, Data: {}", &self.key, &self.data)
    }
}

#[derive(Debug)]
struct SyncResult<T>
    where
T: std::fmt::Display + Clone
{
    value: T,
    error: Option<Box<dyn Error + Send + Sync>>,
}

impl<T: std::fmt::Display + Clone> Default for SyncResult<T> {
    fn default() -> Self {
        SyncResult { value: unsafe { std::mem::zeroed() }, error: None }
    }
}

struct CacheProcessor {
    local_state: HashMap<String, String>,
}

impl CacheProcessor {
    fn new() -> Self {
        CacheProcessor { local_state: HashMap::new() }
    }

    fn process_event(&mut self, event: CacheEvent) -> Result<(), Box<dyn Error + Send + Sync>> {
        if event.key.is_empty() {
            return Err(Box::new(std::io::Error::new(std::io::ErrorKind::InvalidInput, "Empty key provided")))
        }
        println!("Processing event for {}", &event.key);
        self.local_state.insert(event.key.clone(), event.data.clone());
        Ok(())
    }

    fn combine_sync_results(&mut self, events: Vec<CacheEvent>) -> Result<(), Box<dyn Error + Send + Sync>> {
        for event in events {
            match self.process_event(event) {
                Ok(_) => continue,
                Err(e) => { 
                    println!("Critical failure during sync step: {}", e);
                    return Err(Box::new(std::io::Error::new(std::io::ErrorKind::Other, "Sync aborted")))
                }
            }
        }
        Ok(()) 
    }
}

fn main() -> Result<(), Box<dyn Error + Send + Sync>> {
    let mut processor = CacheProcessor::new();
    let events_to_sync = vec![
        CacheEvent { key: "user_profile".into(), data: "json_data_1".into() },
        CacheEvent { key: "settings".into(), data: "json_data_2".into() },
        CacheEvent { key: "metrics".into(), data: "json_data_3".into() },
    ];
    processor.combine_sync_results(events_to_sync)?;
    println!("Sync complete. Final state keys: {:?}", processor.local_state.keys().collect::<Vec<_>>());
    Ok(())
}
